    /**
     * Returns the VTIMEZONE string from the list.
     *
     * @param $zone
     * @return false|string
     */
    public static function getVTimezone($zone)
    {
        if (array_key_exists($zone, self::$vtimezones)) {
            return self::$vtimezones[$zone];
        }

        return false;
    }

    /**
     * Extracts start and end timezone strings from VEvent string.
     *
     * @param $vevent
     * @param $defaultZone
     * @param $startZone
     * @param $endZone
     */
    public static function extractZonesFromVEvent($vevent, $defaultZone, &$startZone, &$endZone)
    {
        if (preg_match("|DTSTART;TZID=(.*):|", $vevent, $matches) && isset($matches[1]) && self::validTimezoneString($matches[1])) {
            $startZone = $matches[1];
        } else {
            $startZone = $defaultZone;
        }

        if (preg_match("|DTEND;TZID=(.*):|", $vevent, $matches) && isset($matches[1]) && self::validTimezoneString($matches[1])) {
            $endZone = $matches[1];
        } else {
            $endZone = $defaultZone;
        }
    }

    /**
     * Generates the VTIMEZONE text without the RRULE -- it simply includes all the transitions that occur between two
     * dates passed as parameters.
     *
     * This function is not used for now, we're using the VTIMEZONE strings from the list instead.
     *
     * @param $zone
     * @param $firstEventStart
     * @param $lastEventStart
     * @return bool|string
     */
    public static function generateVTimezone($zone, $firstEventStart, $lastEventStart)
    {
        try {
            $startTime = strtotime($firstEventStart);
            $endTime = strtotime($lastEventStart);
            $vcalendar = new \Sabre\VObject\Component\VCalendar();
            $timezone = new \DateTimeZone($zone);
            $transitions = $timezone->getTransitions($startTime - 366 * 24 * 60 * 60, $endTime); // -1 year
            $vtimezone = $vcalendar->createComponent("VTIMEZONE");
            $vtimezone->add("TZID", $timezone->getName());
            $from = 0;

            foreach ($transitions as $key => $trans) {
                // skip until the record immediately preceding $starttime, get the skipped record offsets though, because
                // we'll need the previous offset to create TZOFFSETFROM of the first record
                if ($trans['ts'] < $startTime &&
                    array_key_exists($key + 1, $transitions) && $transitions[$key + 1]['ts'] < $startTime
                ) {
                    $from = $trans['offset'];
                    continue;
                }

                $comp = $vcalendar->createComponent($trans['isdst'] ? "DAYLIGHT" : "STANDARD");
                $comp->add(
                    "TZOFFSETFROM",
                    sprintf(($from >= 0 ? "+" : "-") . "%02d%02d", floor(abs($from) / 3600), (abs($from) / 60) % 60)
                );
                $comp->add(
                    "TZOFFSETTO",
                    sprintf(($trans['offset'] >= 0 ? "+" : "-") . "%02d%02d", floor(abs($trans['offset']) / 3600), (abs($trans['offset']) / 60) % 60)
                );
                $comp->add("DTSTART", (new \DateTime($trans['time']))->format('Ymd\THis'));

                empty($trans['abbr']) || $comp->add("TZNAME", $trans['abbr']);

                $from = $trans['offset'];
                $vtimezone->add($comp);
            }

            return $vtimezone->serialize();
        } catch (\Exception $e) {
            return false;
        }
    }

    public static function validTimezoneString(string $timezoneString): bool
    {
        if (empty($timezoneString)) {
            return false;
        }

        try {
            new \DateTimeZone($timezoneString);
            return true;
        } catch (\Exception $e) {
            return false;
        }
    }

    /**
     * @param $dateTimeString
     * @param $fromTimezoneString
     * @param $toTimezoneString
     * @param bool $returnObject
     * @return bool|\DateTime|string
     */
    public static function convertToTimezone($dateTimeString, $fromTimezoneString, $toTimezoneString, bool $returnObject = false)
    {
        try {
            if (!empty($fromTimezoneString) && !empty($toTimezoneString) && $fromTimezoneString != $toTimezoneString) {
                $dateTime = new \DateTime($dateTimeString, new \DateTimeZone($fromTimezoneString));
                $dateTime->setTimezone(new \DateTimeZone($toTimezoneString));
                return $returnObject ? $dateTime : $dateTime->format("Y-m-d H:i:s");
            }

            if ($returnObject) {
                return new \DateTime($dateTimeString, new \DateTimeZone($fromTimezoneString));
            }
        } catch (\Exception $e) {
        }

        return $dateTimeString;
    }

    /**
     * Converts the event's start and end date/time from the event's timezone to the current user timezone.
     *
     * @param array $event
     * @param string $targetTimezoneString
     * @return array
     */
    public static function convertEventToTimezone(array $event, string $targetTimezoneString): array
    {
        try {
            $targetTimezone = new \DateTimeZone($targetTimezoneString);

            if (!empty($event['timezone_start']) && $event['timezone_start'] != $targetTimezoneString) {
                $eventTimezone = new \DateTimeZone($event['timezone_start']);
                $date = new \DateTime($event['start'], $eventTimezone);
                $date->setTimezone($targetTimezone);
                $event['start'] = $date->format("Y-m-d H:i:s");
            }

            if (!empty($event['timezone_end']) && $event['timezone_end'] != $targetTimezoneString) {
                $eventTimezone = new \DateTimeZone($event['timezone_end']);
                $date = new \DateTime($event['end'], $eventTimezone);
                $date->setTimezone($targetTimezone);
                $event['end'] = $date->format("Y-m-d H:i:s");
            }
        } catch (\Exception $e) {
        }

        return $event;
    }

    /**
     * Returns the array of timezoneString => timezoneName, in the format that Roundcube uses on the Preferences /
     * User Interface page.
     *
     * @return array
     */
    public static function getTimezoneList(): array
    {
        $zones = [];
        $result = [];

        foreach (\DateTimeZone::listIdentifiers() as $tzs) {
            try {
                if ($data = self::getTimezoneStandardTimeData($tzs)) {
                    $zones[$data['key']] = [$tzs, $data['offset']];
                }
            } catch (\Exception $e) {}
        }

        ksort($zones);

        foreach ($zones as $zone) {
            list($tzs, $offset) = $zone;
            $result[$tzs] = "(GMT $offset) " . self::getTimezoneLabel($tzs);
        }

        return $result;
    }

    /**
     * Helper function for getTimezoneList();
     *
     * @param $tz
     * @return array|string|string[]
     */
    public static function getTimezoneLabel($tz)
    {
        if (self::$timezoneLabels === null) {
            self::$timezoneLabels = [];
            $labels = [];
            $lang = $_SESSION['language'];
            if ($lang && $lang != 'en_US') {
                if (file_exists(RCUBE_LOCALIZATION_DIR . "$lang/timezones.inc")) {
                    include RCUBE_LOCALIZATION_DIR . "$lang/timezones.inc";
                    self::$timezoneLabels = $labels;
                }
            }
        }

        if (empty(self::$timezoneLabels)) {
            return str_replace('_', ' ', $tz);
        }

        $tokens = explode('/', $tz);
        $key    = 'tz';

        foreach ($tokens as $i => $token) {
            $idx   = strtolower($token);
            $token = str_replace('_', ' ', $token);
            $key  .= ":$idx";

            $tokens[$i] = empty(self::$timezoneLabels[$key]) ? $token : self::$timezoneLabels[$key];
        }

        return implode('/', $tokens);
    }

    /**
     * Helper function for getTimezoneList();
     *
     * @param $tzName
     * @return array
     * @throws \Exception
     */
    private static function getTimezoneStandardTimeData($tzName): array
    {
        $tz = new \DateTimeZone($tzName);
        $date = new \DateTime("now", $tz);
        $count = 12;

        // Move back for a month (up to 12 times) until non-DST date is found
        while ($count > 0 && $date->format('I')) {
            $date->sub(new \DateInterval('P1M'));
            $count--;
        }

        $offset  = (int)$date->format('Z') + 45000;
        $sortKey = sprintf('%06d.%s', $offset, $tzName);

        return [
            'key'    => $sortKey,
            'offset' => $date->format('P'),
        ];
    }
}